class Solution {
public:
    int getMaxRepetitions(string s1, int n1, string s2, int n2) {
        int m = 0, i = 0, j = 0;
        int s1_len = s1.length(), s2_len = s2.length();
        int[] s1_count = new int[s1_len];
        while (m < n1) {
            while (i < s1_len && j < s2_len && s1[i] == s2[j]) {
                s1_count[i] = j + 1;
                i++;
                j++;
            }
            if (j == s2_len) {
                m++;
                j = 0;
            }
            i = (i == s1_len) ? 0 : s1_count[i];
        }
        return m / n2;
    }
};
```

